INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-d0d1b9a2-moex-00234', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '依據最新發布審計準則之規定，下列敘述何者錯誤？', '["對財務報表具重大影響之新會計準則之提前適用，可於查核報告納入「強調事項」段說明", "會計師擬區分查核責任時，除於「查核意見」段及「查核意見之基礎」段提及其他會計師之查 核外，應於查核報告納入其他事項說明未經集團查核團隊查核與由其他會計師查核之範圍", "使受查者繼續經營之能力可能產生重大疑慮之事件或情況存在重大不確定性時所須作之報導， 且於財務報表適當揭露時，會計師可於查核報告中納入「強調事項」段加以敘明該事件或情況， 並指出未因此而修正查核意見", "管理階層如未提供對財務報表編製責任之書面聲明，會計師應對財務報表出具「無法表示意見」 之查核報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00235', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '審計準則700號「財務報表查核報告」依財務報導架構是否追求財務報導應反映企業經營經濟實 質，而將受查者所適用之財務報導架構區分為允當表達架構及遵循架構，下列何者為遵循架構？', '["國際財務報導準則", "美國一般公認會計準則", "企業會計準則", "主管機關法令訂定之財務報導規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00236', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '為使會計師事務所能主動管理其所執行案件之品質，品質管理準則規定事務所應採用風險基礎方', '["建立品質目標", "辨認並評估達成品質目標之風險", "設計並 付諸實行品質風險之因應對策", "針對因應對策執行成果，複核案件品質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00237', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '下列何者為關鍵查核事項之定義？', '["依會計師之專業判斷，對本期財務報表之查核最花時間的項目", "依會計師之專業判斷，對本期財務報表之查核最容易出錯的項目", "依會計師之專業判斷，對本期財務報表之查核最為重要的項目", "依會計師之專業判斷，對本期財務報表之查核中金額最高的項目"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00238', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '有關查核人員針對內部控制缺失之「顯著缺失」應有之專業判斷，下列敘述何者錯誤？', '["查核人員已辨認出非屬內部控制顯著缺失之其他缺失，除非管理階層要求，得不以書面與管理 階層及治理單位溝通，惟須注意該項缺失與其他缺失合併考量是否構成顯著缺失", "查核人員如已辨認出內部控制顯著缺失，如果管理階層已對該等缺失及時採行更正行動，查核 人員仍應將該項缺失與更正行動記載於工作底稿中，但不必再以書面與治理單位溝通", "對內部控制顯著缺失採取更正行動之成本效益評估係管理階層之責任，會計師沒有義務要求管 理階層必須採行更正行動，但仍須將該等內部控制顯著缺失以書面與治理單位溝通", "查核人員以書面溝通內部控制顯著缺失時，應對管理階層及治理單位敘明，查核之目的係對財 務報表表示意見，考量有關之內部控制，僅為設計適當之查核程序，而非對內部控制之有效性 表示意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00239', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '當查核人員複核查核中所發現的未更正不實表達的彙總時，下列查核人員的因應何者較為適當？', '["要求受查者必須對所有的不實表達編製調整分錄", "必須彙總個別非重大不實表逹項目，以評估彙整後的金額是否具重大性", "無須考慮以前年度未更正不實表達對當期財務報表的影響", "僅須要考量會影響損益表的不實表達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00240', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '會計師發現財務比率有以下的變動：存貨週轉率由前期的5.3下降為本期的4.2；應收帳款週轉率 由前期的7.8降為本期的5.6；銷貨收入成長率由前期的8%增加為本期的16%。根據上述資訊， 下列何者最不可能為會計師所作成之結論？', '["因應銷貨急速成長，期末存貨備貨增加", "銷貨集中在期末，導致應收帳款無法及時收現", "銷貨收入有虛增之可能，須增加其他查核程序", "公司縮短授信天數，導致應收帳款週轉率下降"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00241', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '查核人員於執行風險評估程序時，使用分析性程序的主要目的為何？', '["辨認內部控制制度之缺失", "辨認管理階層踰越控制的風險", "獲取支持個別項目聲明之證據", "辨認重大不實表達風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00242', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '依審計準則500號「查核證據」之規定，下列敘述何者錯誤？', '["股票或債券可視為金融工具存在之證明文件，惟檢查此等文件未必可提供有關所有權及價值之 查核證據", "檢查期後應收款項收現之文件，可能提供與截止有關之查核證據，但無法提供與存在及評價有 關之查核證據", "某個人或組織可能具有運用模型以估計無可觀察市場之證券公允價值所需專門知識，若受查者 採用該個人或組織運用該專門知識所作之估計以編製財務報表，則該個人或組織即為管理階層 專家", "若個人或組織僅提供受查者無法取得之非公開交易價格資訊，而受查者於本身之估計方法中採 用此資訊，且查核人員以此資訊作為查核證據時，則非屬受查者對管理階層專家之採用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00243', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '有關固有風險之敘述，下列何者正確？', '["是指財務報表查核前，查核人員不知道的重大不實表達風險", "是指財務報表查核後，查核人員不知道的重大不實表達風險", "是指查核人員運用查核程序無法偵測出錯誤的風險", "是指考量內部控制前，財務報表可能存在之重大不實表達風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "ffdba6b40aee", "answer_pdf_sha1": "6fc05867106a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
